<?php declare(strict_types=1);
require dirname(__DIR__).'/vendor/autoload.php';require dirname(__DIR__).'/app/Helpers/functions.php';
$profiles=new App\Services\StreamingProfileService();
$low=$profiles->selectForPlaylist([['width'=>1280,'height'=>720,'fps'=>30]]);$high=$profiles->selectForPlaylist([['width'=>1280,'height'=>720,'fps'=>30],['width'=>1920,'height'=>1080,'fps'=>60]]);$ultra=$profiles->selectForPlaylist([['width'=>1280,'height'=>720,'fps'=>30],['width'=>3840,'height'=>2160,'fps'=>30]]);
assert($low['resolution']==='1280x720'&&$low['preset']==='veryfast');assert($high['resolution']==='1280x720'&&$high['fps']===30&&$high['preset']==='superfast');assert($ultra['resolution']==='1280x720'&&$ultra['preset']==='superfast');
$builder=new App\Streaming\FfmpegCommandBuilder();$channel=['rtmp_url'=>'rtmp://example.test/live','stream_key'=>'secret'];$settings=['ffmpeg_path'=>'/usr/bin/ffmpeg'];foreach([$low,$high,$ultra]as$profile){$command=$builder->build($channel,'/tmp/list.txt',$settings,true,$profile);assert(str_contains($command,'-vf \'scale='.$profile['resolution'].'\''));assert(str_contains($command,'-preset \''.$profile['preset'].'\''));assert(str_contains($command,'-r '.$profile['fps']));assert(str_contains($command,'-b:v \''.$profile['bitrate'].'\''));}echo "Streaming profile and command selection passed\n";
